  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  // DEV: SQLite (no server needed) — switch to postgresql for production\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─────────────────────────────────────────────────────────────\n// AUTH & TEAM\n// Role values: \"ADMIN\" | \"EDITOR\" | \"VIEWER\"\n// ─────────────────────────────────────────────────────────────\n\nmodel User {\n  id           String  @id @default(uuid())\n  email        String  @unique\n  passwordHash String\n  name         String\n  role         String  @default(\"EDITOR\") // ADMIN | EDITOR | VIEWER\n  avatarUrl    String?\n  isActive     Boolean @default(true)\n\n  // Security\n  failedLoginAttempts Int       @default(0)\n  lockedUntil         DateTime?\n  lastLoginAt         DateTime?\n  lastLoginIp         String?\n\n  refreshTokens RefreshToken[]\n  auditLogs     AuditLog[]\n  blogPosts     BlogPost[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"users\")\n}\n\nmodel RefreshToken {\n  id        String    @id @default(uuid())\n  tokenHash String    @unique\n  userId    String\n  user      User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  expiresAt DateTime\n  revokedAt DateTime?\n  family    String\n  createdAt DateTime  @default(now())\n\n  @@index([userId])\n  @@index([family])\n  @@map(\"refresh_tokens\")\n}\n\n// ─────────────────────────────────────────────────────────────\n// LANDING PAGE CONTENT\n// slug values: \"home\" | \"pricing\" | \"services\" | \"company\" | \"blog\" | \"book_a_demo\"\n// ─────────────────────────────────────────────────────────────\n\nmodel Page {\n  id       String  @id @default(uuid())\n  slug     String  @unique // home | pricing | services | company | blog | book_a_demo\n  title    String\n  metaDesc String?\n\n  // JSON stored as TEXT in SQLite\n  content String @default(\"{}\")\n\n  isPublished Boolean   @default(true)\n  publishedAt DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"pages\")\n}\n\n// ─────────────────────────────────────────────────────────────\n// BLOG\n// status values: \"DRAFT\" | \"PUBLISHED\" | \"ARCHIVED\"\n// ─────────────────────────────────────────────────────────────\n\nmodel BlogPost {\n  id           String  @id @default(uuid())\n  title        String\n  slug         String  @unique\n  excerpt      String?\n  content      String // Rich text HTML (sanitized on save)\n  coverImageId String?\n  coverImage   Media?  @relation(fields: [coverImageId], references: [id])\n\n  status      String    @default(\"DRAFT\") // DRAFT | PUBLISHED | ARCHIVED\n  publishedAt DateTime?\n  scheduledAt DateTime?\n\n  authorId String\n  author   User   @relation(fields: [authorId], references: [id])\n\n  tags PostTag[]\n\n  // SEO\n  metaTitle String?\n  metaDesc  String?\n\n  // Analytics\n  viewCount Int @default(0)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([status, publishedAt])\n  @@index([authorId])\n  @@map(\"blog_posts\")\n}\n\nmodel Tag {\n  id    String    @id @default(uuid())\n  name  String    @unique\n  slug  String    @unique\n  posts PostTag[]\n\n  @@map(\"tags\")\n}\n\nmodel PostTag {\n  postId String\n  tagId  String\n  post   BlogPost @relation(fields: [postId], references: [id], onDelete: Cascade)\n  tag    Tag      @relation(fields: [tagId], references: [id], onDelete: Cascade)\n\n  @@id([postId, tagId])\n  @@map(\"post_tags\")\n}\n\n// ─────────────────────────────────────────────────────────────\n// MEDIA LIBRARY\n// ─────────────────────────────────────────────────────────────\n\nmodel Media {\n  id           String  @id @default(uuid())\n  filename     String\n  originalName String\n  mimeType     String\n  size         Int\n  url          String\n  publicId     String\n  alt          String?\n  width        Int?\n  height       Int?\n\n  blogPosts BlogPost[]\n\n  createdAt DateTime @default(now())\n\n  @@map(\"media\")\n}\n\n// ─────────────────────────────────────────────────────────────\n// ANALYTICS\n// ─────────────────────────────────────────────────────────────\n\nmodel PageView {\n  id        String   @id @default(uuid())\n  page      String\n  ipHash    String\n  referrer  String?\n  userAgent String?\n  country   String?\n  sessionId String?\n  createdAt DateTime @default(now())\n\n  @@index([page, createdAt])\n  @@index([createdAt])\n  @@map(\"page_views\")\n}\n\nmodel Event {\n  id        String   @id @default(uuid())\n  type      String\n  page      String\n  label     String?\n  metadata  String? // JSON as TEXT in SQLite\n  sessionId String?\n  ipHash    String?\n  createdAt DateTime @default(now())\n\n  @@index([type, createdAt])\n  @@index([page, createdAt])\n  @@index([createdAt])\n  @@map(\"events\")\n}\n\n// ─────────────────────────────────────────────────────────────\n// DEMO BOOKINGS\n// status values: \"NEW\" | \"CONTACTED\" | \"COMPLETED\" | \"CANCELLED\"\n// ─────────────────────────────────────────────────────────────\n\nmodel DemoBooking {\n  id      String  @id @default(uuid())\n  name    String\n  email   String\n  company String?\n  phone   String?\n  message String?\n  status  String  @default(\"NEW\") // NEW | CONTACTED | COMPLETED | CANCELLED\n  source  String?\n  notes   String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([status, createdAt])\n  @@index([createdAt])\n  @@map(\"demo_bookings\")\n}\n\n// ─────────────────────────────────────────────────────────────\n// AUDIT LOG\n// ─────────────────────────────────────────────────────────────\n\nmodel AuditLog {\n  id         String   @id @default(uuid())\n  userId     String?\n  user       User?    @relation(fields: [userId], references: [id])\n  action     String\n  resource   String\n  resourceId String?\n  oldValue   String? // JSON as TEXT\n  newValue   String? // JSON as TEXT\n  ipAddress  String?\n  userAgent  String?\n  createdAt  DateTime @default(now())\n\n  @@index([userId])\n  @@index([resource, resourceId])\n  @@index([createdAt])\n  @@map(\"audit_logs\")\n}\n",
